// Calculate yesterday's full-day window.
// Because the schedule runs Tue–Sat, 'yesterday' always resolves to Mon–Fri.
// On a manual trigger it also uses the previous calendar day.

  const now = new Date();
  const yesterday = new Date(now);
  yesterday.setDate(now.getDate() - 1);
  const pad = n => String(n).padStart(2, '0');
  const y = yesterday.getFullYear();
  const m = pad(yesterday.getMonth() + 1);
  const d = pad(yesterday.getDate());
  const cfg = $input.first().json;
  return [{
    json: {
      DOMAIN:         cfg.DOMAIN,
      BASE_URL:       cfg.BASE_URL,
      START_DATETIME: `${y}-${m}-${d} 00:00:00`,
      END_DATETIME:   `${y}-${m}-${d} 23:59:59`,
      FETCH_DATE:     `${y}-${m}-${d}`,
      LIMIT:          '100'
    }
  }];

// Take the keys from the CDR JSON and build a CSV header
const obj = $json;

// Original NetSapiens keys, e.g. "call-orig-caller-id"
const originalKeys = Object.keys(obj);

// Sanitize for n8n Data Table column IDs:
// - replace "-" with "_"
// - remove spaces
// (you can adjust this to your naming preference)
const sanitizedKeys = originalKeys.map(k =>
  k.replace(/-/g, '_').replace(/\s+/g, '')
);

// Build a single header row
const headerRow = sanitizedKeys.join(',');

// Optionally, also build a second row with the original keys
// (for documentation or mapping) – not for import:
const originalRow = originalKeys.join(',');

// Expose both so you can choose how to use them
return [{
  json: {
    header: headerRow,
    original: originalRow,
  },
}];

// Input: items from HTTP Request where each item.json is a CDR object
// Output: 
//   - items with .json.sanitized: object whose keys are safe column names
//   - a single header item (first item) with .json.header: CSV header string

// Helper: sanitize a NetSapiens field name to a n8n/DataTable-safe column ID
function sanitizeKey(key) {
  return key
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_')   // spaces -> _
    .replace(/-/g, '_')     // hyphens -> _
    .replace(/[^a-z0-9_]/g, ''); // drop anything weird
}

// 1) Build sanitized objects for every item
const sanitizedItems = items.map(item => {
  const src = item.json;
  const dst = {};
  for (const [key, value] of Object.entries(src)) {
    const col = sanitizeKey(key);
    dst[col] = value;
  }
  // keep original around if you like
  item.json = {
    original: src,
    sanitized: dst,
  };
  return item;
});

// 2) Build CSV header from sanitized keys of FIRST item
if (sanitizedItems.length > 0) {
  const firstSanitized = sanitizedItems[0].json.sanitized;
  const headerCols = Object.keys(firstSanitized);
  const header = headerCols.join(',');
  // Attach the header to the FIRST item only
  sanitizedItems[0].json.header = header;
}

return sanitizedItems;
